<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <v-col cols="12" sm="12" lg="12" class="pa-2 pb-0">
        <i-card-top
          class="d-flex"
          :useBtnList="buttonUseList"
          @btnAdd="btnAdd()"
          @btnSearch="btnSearch()"
          @btnSave="btnSave()"
          @btnDelete="btnDelete()"
        >
          <template v-slot:body>
            <v-layout overflow-auto>
              <v-row no-gutters class="pa-2" align="center"> </v-row>
            </v-layout>
          </template>
        </i-card-top>
      </v-col>
      <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
        <i-card-vertical headerTitle="그룹 관리" device="web">
          <template v-slot:body>
            <v-layout column>
              <v-col cols="12" md="12" class="row pa-0">
                <v-col cols="12" lg="12" class="pa-0">
                  <DxDataGrid
                    id="groupDataGrid"
                    class="layout-col-height00"
                    width="100%"
                    :ref="dxDataGridRef"
                    :data-source="groups"
                    :remote-operations="false"
                    :hover-state-enabled="true"
                    :allow-column-resizing="true"
                    :allow-column-reordering="true"
                    :row-alternation-enabled="true"
                    :column-auto-width="true"
                    :show-borders="true"
                    :show-row-lines="true"
                    :focused-row-enabled="true"
                    key-expr="id"
                    @row-updating="onRowUpdating"
                    @editing-start="onEditingStart"
                    @selection-changed="onSelectionChanged"
                    @editor-preparing="onEditorPreparing"
                  >
                    <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />

                    <DxSelection :select-all-mode="allMode" show-check-boxes-mode="always" mode="multiple" />

                    <DxColumn
                      data-field="grpAuthCd"
                      caption="권한코드"
                      data-type="string"
                      width="250px"
                      alignment="left"
                      css-class="devest-grid-header-require"
                    >
                    </DxColumn>

                    <DxColumn data-field="grpAuthNm" caption="권한이름" data-type="string" alignment="left" css-class="devest-grid-header-require">
                    </DxColumn>

                    <DxColumn
                      data-field="useYn"
                      data-type="boolean"
                      caption="사용"
                      alignment="center"
                      width="90px"
                      edit-cell-template="checkBoxEditor"
                    />

                    <!-- <DxColumn caption="" awllow-editing="true" data-type="string" /> -->

                    <template #checkBoxEditor="{ data: cellInfo }">
                      <DxCheckBox :value="cellInfo.value == 'Y' ? true : false" :onValueChanged="value => onCheckValueChanged(value, cellInfo)" />
                    </template>
                  </DxDataGrid>
                </v-col>
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { getGroupData, updateGroupData, deleteGroupData } from '@/api/setting/groupManage'

import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가
  name: 'groupManage',
  components: {},
  data() {
    return {
      pageSizes: [5],
      showPageSizeSelector: true,
      dxDataGridRef: 'groupDataGrid',
      groups: [],
      buttonUseList: [
        'btnAdd', //추가
        'btnSearch', //조회
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      allMode: 'allPages'
    }
  },
  computed: {},
  beforeMount() {},
  mounted() {
    this.btnSearch()
  },
  methods: {
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    //------------------------------------------
    //  그룹 조회
    //------------------------------------------
    btnSearch() {
      this.openLoading('searching')

      getGroupData(true)
        .then(res => {
          if (res.success) {
            this.gridInit(this.GetDataGrid(this.dxDataGridRef))

            //super 그룹을 상단에 고정
            let index = res.list.findIndex(e => e.grpAuthCd === 'super')
            let top = res.list.find(e => e.grpAuthCd === 'super')
            res.list.splice(index, 1)
            res.list.unshift(top)

            this.groups = res.list
            this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
          }
        })
        .catch(error => {})
        .finally(() => {
          this.endLoading()
        })
    },
    //------------------------------------------
    //  그룹 추가
    //------------------------------------------
    async btnAdd() {
      let newRow = {
        id: this.groups.length + 1,
        grpAuthCd: '',
        useYn: 'Y'
      }
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      //this.groups.unshift(newRow)
      await this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    //------------------------------------------
    //  그룹 저장
    //------------------------------------------
    btnSave() {
      this.GetDataGrid(this.dxDataGridRef)
        .getSelectedRowsData()
        .then(selectedRows => {
          if (selectedRows.length === 0) {
            this.vToastify(this.$t('selectionData'), 'warn')
            return
          }
          this.vToastifyPrompt(
            this.$t('doSaveData'),
            'info',
            current => {
              this.GetDataGrid(this.dxDataGridRef).beginUpdate()
              this.GetDataGrid(this.dxDataGridRef).saveEditData()

              var pattern = /\s/g

              //필수 입력값 체크
              var index = selectedRows.findIndex(
                element =>
                  element.grpAuthCd == null || element.grpAuthNm == null || element.grpAuthCd.match(pattern) != null || element.grpAuthCd == ''
              )
              if (index >= 0) {
                this.vToastify(`${this.$t('msgReqValidate')}`, 'warn')
                this.GetDataGrid(this.dxDataGridRef).endUpdate()
                return
              }

              this.openLoading('saving')
              //저장 api
              updateGroupData(selectedRows, true)
                .then(res => {
                  if (res.success) {
                    this.gridInit(this.GetDataGrid(this.dxDataGridRef))
                    selectedRows.forEach(element => (element.__created__ = false))
                  }
                })
                .catch(error => {
                  if (error.response && error.response.data) {
                    if (error.response.data.code == -2001) {
                      this.vToastify(this.$t(error.response.data.msg), 'warn')
                    }
                  }
                })
                .finally(() => {
                  this.GetDataGrid(this.dxDataGridRef).endUpdate()
                  this.endLoading()
                })
            },
            null,
            true
          )
        })
    },
    //------------------------------------------
    //  그룹 삭제
    //------------------------------------------
    btnDelete() {
      let createdRows = []
      let selectedRows = []
      this.GetDataGrid(this.dxDataGridRef)
        .getSelectedRowsData()
        .then(allSelectedRows => {
          if (allSelectedRows.length === 0) {
            this.vToastify(this.$t('selectionData'), 'warn')
            return
          }
          allSelectedRows.forEach(item => {
            if (item.__created__ == true) createdRows.push(item)
            else selectedRows.push(item)
          })
          if (selectedRows.length === 0) {
            this.deleteCallBack(createdRows)
            return
          }
          this.vToastifyPrompt(
            this.$t('doDeleteData'),
            'info',
            current => {
              this.GetDataGrid(this.dxDataGridRef).beginUpdate()
              this.GetDataGrid(this.dxDataGridRef).saveEditData()

              var index = selectedRows.findIndex(element => element.grpAuthCd == 'super')
              if (index >= 0) {
                this.vToastify(this.$t('슈퍼유저 권한은 삭제할 수 없습니다.'), 'warn')
                this.GetDataGrid(this.dxDataGridRef).endUpdate()
                return
              }

              this.openLoading('deleting')
              //삭제 api
              deleteGroupData(selectedRows, true)
                .then(res => {
                  if (res.success) {
                    this.deleteCallBack(allSelectedRows)
                  }
                })
                .catch(error => {})
                .finally(() => {
                  this.GetDataGrid(this.dxDataGridRef).endUpdate()
                  this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
                  this.endLoading()
                })
            },
            null,
            true
          )
        })
    },

    ///////////////////////////////////////
    /*           DataGrid Event          */
    ///////////////////////////////////////
    onCheckValueChanged(value, cellInfo) {
      cellInfo.setValue(cellInfo.value === 'Y' ? 'N' : 'Y')
      this.GetDataGrid(this.dxDataGridRef).selectRows(cellInfo.row.key, true)
      cellInfo.component.updateDimensions()
    },

    ///////////////////////////////////////
    /*             etc Event             */
    ///////////////////////////////////////
    deleteCallBack(selectedRows) {
      var index = null
      selectedRows.forEach(key => {
        index = this.groups.findIndex(obj => obj == key)
        this.groups.splice(index, 1)
      })
    },

    onEditingStart(e) {
      //grpAuthCd는 추가된 행이 아니면 수정 불가능하게 설정
      if (e.column.dataField == 'grpAuthCd' && !e.data.__created__) e.cancel = true
      else e.cancel = false
      //super그룹 수정 불가능하게 설정
      if (e.key === 'super') e.cancel = true
    },

    onSelectionChanged(e) {
      //super그룹 selection 불가능하게 설정
      this.GetDataGrid(this.dxDataGridRef)
        .getSelectedRowKeys()
        .then(selectedRows => {
          selectedRows.forEach(element => {
            if (element === 'super') {
              this.GetDataGrid(this.dxDataGridRef).deselectRows(element)
              return
            }
          })
        })
    }
  }
}
</script>
